const c = $input.first().json;
const tactics = (c.mitre_tactics || []).join(', ') || 'Unknown';
const techniques = (c.mitre_techniques || []).join(', ') || 'Unknown';
const tools = (c.tools || []).join(', ') || 'Unknown';

const schema = '{"title":"short demo title","description":"2-3 sentence customer-facing description","mitre_tactics":["Tactic1","Tactic2"],"mitre_techniques":[{"id":"T1234.001","name":"Technique Name"}],"tools":["tool1","tool2"],"atomic_tests":["T1234.001-1"],"caldera_ability":"slug-id","audience":"Technical","platform":"windows","execution_engine":"atomic","expected_detections":[{"detection":"specific detection alert name","severity":"high"}],"talking_points":{"universal":["key point 1","key point 2","key point 3"],"healthcare":["healthcare-specific insight"],"financial_services":["financial-specific insight"],"manufacturing":["manufacturing-specific insight"],"retail":["retail-specific insight"]},"se_runbook":{"setup":"Pre-demo setup notes for the SE","steps":["Step 1: configure environment","Step 2: run simulation","Step 3: review detections"],"talking_points_timing":"Mention talking points after first alert fires"}}';

const prompt = `You are a cybersecurity expert building scenarios for MDR (Managed Detection & Response) product demos. Convert this real-world attack case into a structured demo scenario.

Attack Case:
Title: ${c.title}
Description: ${c.description}
Threat Actor: ${c.threat_actor || 'Unknown'}
Source: ${c.source}
Industry: ${c.industry}
MITRE Tactics: ${tactics}
MITRE Techniques: ${techniques}
Tools/Malware: ${tools}
Additional Context: ${c.context || 'None provided'}

Return ONLY valid JSON matching this exact schema with no markdown, no code fences, no explanation:
${schema}`;

return [{ json: { prompt: prompt } }];

const fs = require('fs');
const https = require('https');
const http = require('http');
const prompt = $input.first().json.prompt;
let provider = 'ollama', apiKey = '', model = '';
try {
  const cfg = JSON.parse(fs.readFileSync('/data/scenarios/ai-config.json', 'utf-8'));
  provider = cfg.provider || 'ollama';
  apiKey = cfg.apiKey || '';
  model = cfg.model || '';
} catch(e) {
  provider = $env.AI_PROVIDER || 'ollama';
  apiKey = $env.AI_API_KEY || '';
  model = $env.AI_MODEL || '';
}
const defaults = { anthropic: 'claude-sonnet-4-20250514', openai: 'gpt-4o', gemini: 'gemini-2.5-flash', ollama: $env.OLLAMA_MODEL || 'llama3.2:3b' };
const useModel = model || defaults[provider] || defaults.ollama;
let url, headers, body;
switch (provider) {
  case 'anthropic':
    url = 'https://api.anthropic.com/v1/messages';
    headers = { 'x-api-key': apiKey, 'anthropic-version': '2023-06-01', 'content-type': 'application/json' };
    body = JSON.stringify({ model: useModel, max_tokens: 4096, messages: [{ role: 'user', content: prompt }] });
    break;
  case 'openai':
    url = 'https://api.openai.com/v1/chat/completions';
    headers = { 'Authorization': 'Bearer ' + apiKey, 'Content-Type': 'application/json' };
    body = JSON.stringify({ model: useModel, messages: [{ role: 'user', content: prompt }] });
    break;
  case 'gemini':
    url = 'https://generativelanguage.googleapis.com/v1beta/models/' + useModel + ':generateContent?key=' + apiKey;
    headers = { 'Content-Type': 'application/json' };
    body = JSON.stringify({ contents: [{ parts: [{ text: prompt }] }] });
    break;
  default:
    url = ($env.OLLAMA_HOST || 'http://host.docker.internal:11434') + '/api/generate';
    headers = { 'Content-Type': 'application/json' };
    body = JSON.stringify({ model: useModel, prompt, stream: false });
}

const parsed = new URL(url);
const transport = parsed.protocol === 'https:' ? https : http;
const data = await new Promise((resolve, reject) => {
  const req = transport.request(url, { method: 'POST', headers, timeout: 120000 }, (res) => {
    let chunks = '';
    res.on('data', d => chunks += d);
    res.on('end', () => {
      if (res.statusCode >= 400) reject(new Error('AI provider error (' + provider + '): ' + res.statusCode + ' ' + chunks));
      else resolve(chunks);
    });
  });
  req.on('error', reject);
  req.on('timeout', () => { req.destroy(); reject(new Error('AI request timed out')); });
  if (body) req.write(body);
  req.end();
});

const response = JSON.parse(data);
return [{ json: { provider, response } }];

const { provider, response } = $input.first().json;
let text;
switch (provider) {
  case 'anthropic': text = response.content && response.content[0] ? response.content[0].text : ''; break;
  case 'openai': text = response.choices && response.choices[0] ? response.choices[0].message.content : ''; break;
  case 'gemini': text = response.candidates && response.candidates[0] ? response.candidates[0].content.parts[0].text : ''; break;
  default: text = response.response || '';
}
return [{ json: { response: text } }];

const raw = $input.first().json.response || '';
const cleaned = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
const c = $('Parse Case Input').item.json;

let scenario;
try {
  scenario = JSON.parse(cleaned);
} catch(e) {
  scenario = {
    title: c.title || 'Custom Scenario',
    description: c.description || '',
    mitre_tactics: c.mitre_tactics || [],
    mitre_techniques: (c.mitre_techniques || []).map(t => typeof t === 'string' ? {id:t, name:t} : t),
    tools: c.tools || [],
    atomic_tests: [],
    caldera_ability: '',
    audience: 'Technical',
    platform: 'windows',
    execution_engine: 'atomic',
    expected_detections: [],
    talking_points: { universal: [] },
    se_runbook: { setup: '', steps: [], talking_points_timing: '' }
  };
}

if (scenario.mitre_techniques) {
  scenario.mitre_techniques = scenario.mitre_techniques.map(t =>
    typeof t === 'string' ? {id: t, name: t} : t
  );
}

const scenarioId = 'SCN-CASE-' + Date.now().toString().slice(-6);
scenario.id = scenarioId;
scenario.source = 'case-submission';
scenario.ai_provider = $('Call AI Provider').first().json.provider || 'unknown';
scenario.case_id = c.case_id;
scenario.submitted_by = c.submitted_by;
if (!scenario.industry) scenario.industry = c.industry || 'universal';

return [{ json: scenario }];

const fs = require('fs');
const filePath = '/data/scenarios/scenarios.json';
let db;
try { db = JSON.parse(fs.readFileSync(filePath, 'utf8')); }
catch(e) { db = { version: '1.0', last_updated: '', scenarios: [] }; }

const s = $input.first().json;
const idx = db.scenarios.findIndex(x => x.id === s.id);
if (idx >= 0) { db.scenarios[idx] = s; } else { db.scenarios.push(s); }
db.last_updated = new Date().toISOString().split('T')[0];
fs.writeFileSync(filePath, JSON.stringify(db, null, 2), 'utf8');

return [{ json: { status: 'queued', scenario_id: s.id, case_id: s.case_id, message: 'Scenario generated and added to catalog' } }];
